def assess(record: dict) -> str:
    required = {"business_rule", "case_id", "extra_policy", "json_schema", "valid_fixture"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record["extra_policy"]=="forbid" and record["business_rule"]) else "REJECT_SCHEMA"

